import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const LABELS = {
  true: { text: '진행중', color: '#4caf50' },
  false: { text: '모집완료', color: '#f44336' },
};

function PostsList() {
  const [posts, setPosts] = useState([]);
  const [showRecruiting, setShowRecruiting] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetch(`/api/posts${showRecruiting ? '?recruiting=true' : ''}`)
      .then(res => res.json())
      .then(data => setPosts(data.posts || []));
  }, [showRecruiting]);

  return (
    <div style={{ maxWidth: 900, margin: '40px auto' }}>
      <h2>축구팀 모집 게시판</h2>
      <label style={{ float: 'right', marginBottom: 10 }}>
        <input type="checkbox" checked={showRecruiting} onChange={e => setShowRecruiting(e.target.checked)} />
        진행중만 표시
      </label>
      <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff' }}>
        <thead>
          <tr style={{ background: '#eee' }}>
            <th style={{ width: 100 }}>상태</th>
            <th>제목</th>
            <th style={{ width: 120 }}>작성자</th>
            <th style={{ width: 140 }}>작성일</th>
            <th style={{ width: 80 }}>조회수</th>
            <th style={{ width: 220 }}>태그</th>
          </tr>
        </thead>
        <tbody>
          {posts.map(post => (
            <tr key={post.id} style={{ cursor: 'pointer' }} onClick={() => navigate(`/posts/${post.id}`)}>
              <td>
                <span style={{
                  display: 'inline-block',
                  padding: '2px 10px',
                  borderRadius: 12,
                  background: LABELS[post.is_recruiting]?.color,
                  color: '#fff',
                  fontWeight: 600,
                  fontSize: 13,
                }}>{LABELS[post.is_recruiting]?.text}</span>
              </td>
              <td>{post.title}</td>
              <td>{post.author}</td>
              <td>{new Date(post.created_at).toLocaleDateString()}</td>
              <td>{post.views}</td>
              <td>
                {[post.region, post.age_group, post.skill_level]
                  .filter(Boolean)
                  .map((tag, i) => (
                    <span key={i} style={{
                      display: 'inline-block',
                      background: '#1976d2',
                      color: '#fff',
                      borderRadius: 8,
                      padding: '2px 8px',
                      marginRight: 4,
                      fontSize: 12,
                    }}>{tag}</span>
                  ))}
                {post.extra_tags && post.extra_tags.split(',').map((tag, i) => (
                  <span key={i} style={{
                    display: 'inline-block',
                    background: '#607d8b',
                    color: '#fff',
                    borderRadius: 8,
                    padding: '2px 8px',
                    marginRight: 4,
                    fontSize: 12,
                  }}>{tag.trim()}</span>
                ))}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      <button style={{ marginTop: 24, float: 'right' }} onClick={() => navigate('/posts/new')}>글 작성</button>
    </div>
  );
}

export default PostsList;
